#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv_m = 1.0 - abs( fract( vUv * 0.5 ) * 2.0 - 1.0 ); // Eo.S' mirror code
ret.x = mix( GetPixel(vUvOriginal), texture(sampler_fc_main, uv_m), 0.6).x -0.03; // a little bit of motion blur

vec2 zoom = 1.62;
vec2 c = vec2(0.48,0.748);
vec2 my_uv = (vUvOriginal-0.5)*zoom;
my_uv = vec2(my_uv.x*my_uv.x - my_uv.y*my_uv.y, 2*my_uv.x*my_uv.y) + c;

ret.y = texture(sampler_fc_main, my_uv ).y + 0.004; // static julia fractal

ret.z = mix(texture(sampler_fc_main, mix(vUvOriginal,uv_m,-0.2)).y, // reverbed julia fractal
             GetPixel(vUvOriginal).z,
             0.6); // motion blur again

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 d = uTexSize.zw*4;
vec3 dx = ( GetBlur1( vUv + vec2(1,0)*d) - GetBlur1( vUv - vec2(1,0)*d) );
vec3 dy = ( GetBlur1( vUv + vec2(0,1)*d) - GetBlur1( vUv - vec2(0,1)*d) );

float sin = q11;
float cos = q12;
float scale = 1;

vec2 uv6 = (vUv-0.5)*uAspect.xy*2.4;
       uv6 = scale*vec2( cos*uv6.x - sin*uv6.y, sin*uv6.x + cos*uv6.y); // rotation
       uv6 = 0.5 + uv6*uAspect.zw + vec2(q13,q14);

       uv6 = 1.0 - abs( fract( uv6 * 0.5 ) * 2.0 - 1.0 ); // Eo.S' mirror code
       uv6 -= vec2(dx.z,dy.z)*0.1;

vec2 uv_x = 0.5 + (uv6-0.5)*0.9;
vec2 uv_y = uv6 - vec2(q13,q14);

d = uTexSize.zw*12;
dx = ( GetBlur1( uv_x + vec2(1,0)*d) - GetBlur1( uv_x - vec2(1,0)*d) );
dy = ( GetBlur1( uv_x + vec2(0,1)*d) - GetBlur1( uv_x - vec2(0,1)*d) );


ret = mix(mix(GetPixel(uv_x).x*vec3(1,0,0),
                vec3(-0.1,-1,-1),
                GetPixel(uv_y).y),
           vec3(1,1,0),
           length(vec2(dx.x,dy.x)));
ret = mix(ret,vec3(-0.5,2,3),GetPixel(vUv).z*0.4);

//ret = GetPixel(uv_y).y;

  fragColor = ret;
}
